INSERT INTO `que_fill_py_1` (`q_id`, `unit_id`, `title`, `text`, `input`, `output`, `code`, `options`, `answer`, `explanation`, `example`) VALUES

(
  214,
  15,
  '日期格式化',
  '小美有一个格式为`"2025-07-15"`的日期字符串，她想把它变成`"15/07/2025"`的格式。请帮她完成下面的代码。',
  NULL,
  '["15/07/2025"]',
  '{"segments": [{"type": "code_block", "lines": [{"type": "code_line", "value": "date_str = \\\"2025-07-15\\\""}, {"type": "code_line", "value": "# 使用切片提取年、月、日"}]}, {"type": "code_inline", "parts": [{"type": "code", "value": "year = date_str["}, {"type": "slot", "index": 0}, {"type": "code", "value": "]"}]}, {"type": "code_inline", "parts": [{"type": "code", "value": "month = date_str["}, {"type": "slot", "index": 1}, {"type": "code", "value": "]"}]}, {"type": "code_inline", "parts": [{"type": "code", "value": "day = date_str["}, {"type": "slot", "index": 2}, {"type": "code", "value": "]"}]}, {"type": "code_block", "lines": [{"type": "code_line", "value": "new_date_str = day + \\\"/\\\" + month + \\\"/\\\" + year"}, {"type": "code_line", "value": "print(new_date_str)"}]}]}',
